gold_query:
SELECT DISTINCT ?paper ?paperLabel ?venue ?venueLabel
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 .
    ?contribution orkgp:P135046 ?venue .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?venue rdfs:label ?venueLabel . }
}
ORDER BY ?paperLabel ?venueLabel

SELECT DISTINCT ?paper ?paperLabel ?researchParadigm ?researchParadigmLabel
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001.               
    ?contribution orkgp:P57003 ?researchParadigm .
    ?contribution orkgp:P135046 ?venue .
    ?venue rdfs:label ?venue_name .

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?researchParadigm rdfs:label ?researchParadigmLabel . }
}
ORDER BY ?paperLabel ?researchParadigmLabel

SELECT DISTINCT ?paper ?paperLabel ?researchQuestion ?researchQuestionLabel ?questionWording
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 .
    ?contribution orkgp:P37330 ?researchQuestion .

    ?contribution orkgp:P135046 ?venue .
    ?venue rdfs:label ?venue_name .

    ?researchQuestion orkgp:P44139 ?questionWording .

    OPTIONAL {?researchQuestion rdfs:label ?researchQuestionLabel}
    OPTIONAL {?paper rdfs:label ?paperLabel .}

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
ORDER BY ?paperLabel ?questionWording

SELECT ?paper ?paperLabel
       (GROUP_CONCAT(DISTINCT ?questionTypeLabel; separator=" | ") AS ?questionTypes)
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue .
    ?contribution orkgp:P37330 ?researchQuestion .
    ?researchQuestion orkgp:P41928 ?questionType .

    ?venue rdfs:label ?venue_name .
    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?questionType rdfs:label ?questionTypeLabel . }
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?paper ?paperLabel
ORDER BY ?paperLabel

SELECT DISTINCT ?paper ?paperLabel ?dataType ?dataTypeLabel
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue .

    ?contribution orkgp:P56008 ?dataCollection .
    ?dataCollection orkgp:DATA ?researchData .
    ?researchData orkgp:P7055 ?dataType .
    ?venue rdfs:label ?venue_name .
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)

    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?dataType rdfs:label ?dataTypeLabel . }
}
ORDER BY ?paperLabel ?dataTypeLabel

