SELECT ?decade ?data_type ?data_typeLabel
       ?research_paradigm ?research_paradigmLabel
       ?method_type ?method_typeLabel
       ?paper_count
WHERE {
    {
        SELECT ?decade ?data_type ?data_typeLabel (MAX(?paper_count) AS ?max_paper_count)
        WHERE {
            {
                SELECT ?decade ?data_type ?data_typeLabel
                       ?research_paradigm ?research_paradigmLabel
                       ?method_type ?method_typeLabel
                       (COUNT(DISTINCT ?paper) AS ?paper_count)
                WHERE {
                    ?paper orkgp:P31 ?contribution ;
                           orkgp:P29 ?year .

                    ?contribution a orkgc:C27001 ;
                                  orkgp:P135046 ?venue ;
                                  orkgp:P57003 ?research_paradigm ;
                                  orkgp:P56008 ?data_collection .

                    ?venue rdfs:label ?venue_name .

                    ?research_paradigm rdfs:label ?research_paradigmLabel .

                    ?data_collection rdfs:label ?dc_label ;
                                     orkgp:DATA ?research_data ;
                                     orkgp:P1005 ?dc_method .

                    ?research_data orkgp:P7055 ?data_type .
                    ?data_type rdfs:label ?data_typeLabel .

                    ?dc_method orkgp:P94003 ?method_type .
                    ?method_type rdfs:label ?method_typeLabel .

                    BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10)) * 10 AS ?decade_start)
                    BIND(CONCAT(STR(?decade_start), "s") AS ?decade)

                    FILTER(?dc_label != "no collection"^^xsd:string)
                    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
                    FILTER(
                        ?data_typeLabel = "qualitative"^^xsd:string ||
                        ?data_typeLabel = "quantitative"^^xsd:string
                    )
                }
                GROUP BY ?decade ?data_type ?data_typeLabel
                         ?research_paradigm ?research_paradigmLabel
                         ?method_type ?method_typeLabel
            }
        }
        GROUP BY ?decade ?data_type ?data_typeLabel
    }

    {
        SELECT ?decade ?data_type ?data_typeLabel
               ?research_paradigm ?research_paradigmLabel
               ?method_type ?method_typeLabel
               (COUNT(DISTINCT ?paper) AS ?paper_count)
        WHERE {
            ?paper orkgp:P31 ?contribution ;
                   orkgp:P29 ?year .

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue ;
                          orkgp:P57003 ?research_paradigm ;
                          orkgp:P56008 ?data_collection .

            ?venue rdfs:label ?venue_name .

            ?research_paradigm rdfs:label ?research_paradigmLabel .

            ?data_collection rdfs:label ?dc_label ;
                             orkgp:DATA ?research_data ;
                             orkgp:P1005 ?dc_method .

            ?research_data orkgp:P7055 ?data_type .
            ?data_type rdfs:label ?data_typeLabel .

            ?dc_method orkgp:P94003 ?method_type .
            ?method_type rdfs:label ?method_typeLabel .

            BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10)) * 10 AS ?decade_start)
            BIND(CONCAT(STR(?decade_start), "s") AS ?decade)

            FILTER(?dc_label != "no collection"^^xsd:string)
            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
            FILTER(
                ?data_typeLabel = "qualitative"^^xsd:string ||
                ?data_typeLabel = "quantitative"^^xsd:string
            )
        }
        GROUP BY ?decade ?data_type ?data_typeLabel
                 ?research_paradigm ?research_paradigmLabel
                 ?method_type ?method_typeLabel
    }

    FILTER(?paper_count = ?max_paper_count)
}
ORDER BY ?decade ?data_typeLabel DESC(?paper_count) ?research_paradigmLabel ?method_typeLabel

SELECT ?inferential_statistics_group
       ?ml_algorithm
       ?ml_algorithmLabel
       ?metric_value
       (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    {
        SELECT DISTINCT ?paper ?inferential_statistics_group ?ml_algorithm ?ml_algorithmLabel ?metric_value
        WHERE {
            ?paper orkgp:P31 ?contribution .

            OPTIONAL { ?paper rdfs:label ?paperLabel . }

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue ;
                          orkgp:P15124 ?data_analysis .

            ?venue rdfs:label ?venue_name .

            ?data_analysis rdfs:label ?da_label .

            ?data_analysis orkgp:P57016 ?machine_learning .

            ?machine_learning orkgp:P2001 ?ml_algorithm .

            OPTIONAL { ?ml_algorithm rdfs:label ?ml_algorithmLabel . }

            ?machine_learning orkgp:P2006 ?metric .

            {
                ?metric orkgp:P5073 ?recall .
                BIND("recall"^^xsd:string AS ?metric_value)
            }
            UNION
            {
                ?metric orkgp:P3004 ?precision .
                BIND("precision"^^xsd:string AS ?metric_value)
            }
            UNION
            {
                ?metric orkgp:P18048 ?accuracy .
                BIND("accuracy"^^xsd:string AS ?metric_value)
            }
            UNION
            {
                ?metric orkgp:P59137 ?f_score .
                BIND("f-score"^^xsd:string AS ?metric_value)
            }

            BIND(
                IF(
                    EXISTS {
                        ?data_analysis orkgp:P56043 ?inferential_statistics .
                    },
                    "with inferential statistics"^^xsd:string,
                    "without inferential statistics"^^xsd:string
                ) AS ?inferential_statistics_group
            )

            FILTER(?da_label != "no analysis"^^xsd:string)

            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
    }
}

GROUP BY ?inferential_statistics_group ?ml_algorithm ?ml_algorithmLabel ?metric_value
ORDER BY ?inferential_statistics_group DESC(?paper_count) ?ml_algorithmLabel ?metric_value

SELECT ?year
